import React, { useState } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import BookingModal from './components/BookingModal';
import HomePage from './pages/HomePage';
import CarsPage from './pages/CarsPage';
import CarDetailPage from './pages/CarDetailPage';
import MapPage from './pages/MapPage';
import AdminPage from './pages/AdminPage';
import ContactPage from './pages/ContactPage';
import AuthPage from './pages/AuthPage';
import TermsPage from './pages/TermsPage';

const CARS = [
  { id: 1, name: "BMW 520d", category: "Бизнес", year: 2023, seats: 5, transmission: "Автомат", fuel: "Дизель", engine: "2.0L Turbo", hp: 190, price: 120, lat: 53.9045, lng: 27.5615, address: "пр. Независимости, 31", available: true, rating: 4.8, trips: 124, desc: "Элегантный бизнес-седан с превосходным комфортом и динамикой." },
  { id: 2, name: "Mercedes-Benz C200", category: "Бизнес", year: 2022, seats: 5, transmission: "Автомат", fuel: "Бензин", engine: "1.5L Turbo", hp: 204, price: 140, lat: 53.8934, lng: 27.5479, address: "ул. Немига, 12", available: true, rating: 4.9, trips: 98, desc: "Роскошный седан с передовыми технологиями." },
  { id: 3, name: "Audi A4", category: "Бизнес", year: 2023, seats: 5, transmission: "Автомат", fuel: "Бензин", engine: "2.0 TFSI", hp: 204, price: 130, lat: 53.9108, lng: 27.5888, address: "ул. Сурганова, 57", available: true, rating: 4.7, trips: 87, desc: "Спортивная элегантность и технологичность." },
  { id: 4, name: "Volkswagen Polo", category: "Эконом", year: 2022, seats: 5, transmission: "Механика", fuel: "Бензин", engine: "1.6 MPI", hp: 110, price: 55, lat: 53.8772, lng: 27.5145, address: "ул. Притыцкого, 83", available: true, rating: 4.5, trips: 213, desc: "Надёжный и экономичный городской автомобиль." },
  { id: 5, name: "Toyota Camry", category: "Комфорт", year: 2023, seats: 5, transmission: "Автомат", fuel: "Бензин", engine: "2.5L", hp: 200, price: 95, lat: 53.9201, lng: 27.5769, address: "пр. Машерова, 11", available: false, rating: 4.6, trips: 156, desc: "Легендарная надёжность Toyota." },
  { id: 6, name: "Kia Rio", category: "Эконом", year: 2021, seats: 5, transmission: "Автомат", fuel: "Бензин", engine: "1.6L", hp: 123, price: 45, lat: 53.8618, lng: 27.6742, address: "пр. Партизанский, 150", available: true, rating: 4.3, trips: 301, desc: "Популярный и доступный автомобиль." },
  { id: 7, name: "Hyundai Sonata", category: "Комфорт", year: 2022, seats: 5, transmission: "Автомат", fuel: "Бензин", engine: "2.5L", hp: 180, price: 85, lat: 53.9350, lng: 27.6510, address: "ул. Богдановича, 155", available: true, rating: 4.4, trips: 178, desc: "Стильный седан с просторным салоном." },
  { id: 8, name: "Range Rover Evoque", category: "Премиум", year: 2023, seats: 5, transmission: "Автомат", fuel: "Дизель", engine: "2.0L D200", hp: 200, price: 200, lat: 53.9050, lng: 27.5520, address: "ул. Интернациональная, 25", available: true, rating: 4.9, trips: 42, desc: "Премиальный кроссовер с безупречным стилем." },
  { id: 9, name: "Škoda Octavia", category: "Комфорт", year: 2022, seats: 5, transmission: "Автомат", fuel: "Дизель", engine: "2.0 TDI", hp: 150, price: 75, lat: 53.8890, lng: 27.5960, address: "ул. Козлова, 7", available: true, rating: 4.5, trips: 190, desc: "Практичный и вместительный автомобиль." },
];

export default function App() {
  const [modalCar, setModalCar] = useState(null);
  const [bookings, setBookings] = useState([]);
  const [showSuccess, setShowSuccess] = useState(false);
  const [showTerms, setShowTerms] = useState(false);
  const [user, setUser] = useState(() => {
    const saved = localStorage.getItem('user');
    return saved ? JSON.parse(saved) : null;
  });

  const handleLogin = (userData, token) => {
    localStorage.setItem('token', token);
    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
  };

  const handleBook = (car) => {
    if (!user) return;
    setModalCar(car);
  };

  const handleSubmitBooking = (formData) => {
    const booking = {
      id: Date.now(),
      car: modalCar,
      ...formData,
      status: 'pending',
      createdAt: new Date().toLocaleDateString('ru-RU'),
    };
    setBookings(prev => [booking, ...prev]);
    setModalCar(null);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 4000);
  };

  const updateBookingStatus = (id, status) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
  };

  const pendingCount = bookings.filter(b => b.status === 'pending').length;

  if (!user) {
    return <AuthPage onLogin={handleLogin} />;
  }

  return (
    <div className="pr-app">
      <Navbar pendingCount={pendingCount} user={user} onLogout={handleLogout} />

      <Routes>
        <Route path="/" element={<HomePage cars={CARS} onBook={handleBook} />} />
        <Route path="/cars" element={<CarsPage cars={CARS} onBook={handleBook} />} />
        <Route path="/cars/:id" element={<CarDetailPage cars={CARS} onBook={handleBook} />} />
        <Route path="/map" element={<MapPage cars={CARS} onCarClick={handleBook} />} />
        <Route path="/contact" element={<ContactPage />} />
        {user.role === 'admin' && (
          <Route path="/admin" element={<AdminPage bookings={bookings} onUpdateStatus={updateBookingStatus} />} />
        )}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>

      <Footer onShowTerms={() => setShowTerms(true)} />

      {modalCar && (
        <BookingModal car={modalCar} onClose={() => setModalCar(null)} onSubmit={handleSubmitBooking} />
      )}

      {showTerms && <TermsPage onClose={() => setShowTerms(false)} />}

      {showSuccess && (
        <div className="success-popup">
          <div className="success-icon">✓</div>
          <div><h4>Заявка отправлена!</h4><p>Мы свяжемся с вами</p></div>
        </div>
      )}
    </div>
  );
}
